import{Socket}from"net";import{PacketHeader}from"../constants";import Queue from"queue";export default function(callback,customSocket=null){const TCPclient=customSocket??new Socket;let remaining=0;let payload=Buffer.allocUnsafe(0);const Q=new Queue({autostart:true,concurrency:1});TCPclient.on("data",bytes=>{let frame=Buffer.from(bytes);Q.push(finish=>{(function(){while(frame.length!==0){if(remaining===0&&PacketHeader.matches(frame)){const correctLength=frame.readUInt16LE(4);if(frame.length-6<correctLength){payload=frame;remaining=correctLength-(frame.length-6);return}else{callback(frame.slice(0,correctLength+6));frame=frame.slice(correctLength+6);remaining=0;payload=Buffer.allocUnsafe(0)}}else if(remaining>0){const extractN=Math.min(remaining,frame.length);payload=Buffer.concat([payload,frame.slice(0,extractN)]);remaining-=extractN;frame=frame.slice(extractN);if(remaining===0){callback(payload);payload=Buffer.allocUnsafe(0)}if(remaining<0){throw Error("Extracted more bytes than the payload specified")}}else{throw new Error("Header not matching and remaining is zero")}}})();finish()})});return TCPclient}